function solve(nums: number[], k: number): number {
    nums.sort((a, b) => a - b);
    let maxLen = 1;
    const n = nums.length;

    for (let i = 0; i < n; i++) {
        const target = nums[i] * k;
        let low = i;
        let high = n - 1;
        let res = i - 1;

        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (nums[mid] <= target) {
                res = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        if (res >= i) {
            const currentLen = res - i + 1;
            if (currentLen > maxLen) {
                maxLen = currentLen;
            }
        }
    }

    return n - maxLen;
}
